  await t('[bb] Shift+Tab on a top-level list item makes a valid <p>', () => { E.setHTML('<ul><li>alpha</li><li>beta</li></ul>'); const li = E.node.querySelector('li'); const r = document.createRange(); r.selectNodeContents(li); r.collapse(true); const s = window.getSelection(); s.removeAllRanges(); s.addRange(r); E.saveRange(); E.promoteListItem(); const p = E.node.querySelector('p'); const ok = !!p && p.textContent === 'alpha' && !p.closest('li') && E.node.querySelector('ul') && E.node.querySelector('ul').children.length === 1; return ok; });
