  await t('[bb] Track Changes: typing over a selection records a <del> (no data loss)', () => { WC.Review.trackOn = true; E.setHTML('<p>hello world</p>'); const tn = E.node.querySelector('p').firstChild; const r = document.createRange(); r.setStart(tn, 0); r.setEnd(tn, 5); const s = window.getSelection(); s.removeAllRanges(); s.addRange(r); E.saveRange(); WC.Review.insertTracked('HI'); const del = E.node.querySelector('del.wc-del'); const ins = E.node.querySelector('ins.wc-ins'); const ok = !!del && /hello/.test(del.textContent) && !!ins && /HI/.test(ins.textContent) && /world/.test(E.node.textContent); WC.Review.trackOn = false; return ok; });
