  await t('[bb] Pagination never injects a gap spacer inside a table cell', () => { E.setView('print'); let f = ''; for (let i = 0; i < 25; i++) f += '<p>filler line ' + i + '</p>'; let rows = ''; for (let i = 0; i < 10; i++) rows += '<tr><td>r' + i + 'c1</td><td>r' + i + 'c2</td></tr>'; E.setHTML(f + '<table>' + rows + '</table>'); E.repaginate(); return E.node.querySelectorAll('td .wc-page-gap, table .wc-page-gap, td .wc-gap-band').length === 0; });
  await t('[bb] Format Painter across paragraphs keeps block structure', () => { E.setView('print'); E.setHTML('<p><span style="color:rgb(255,0,0)">red</span></p><p>one two</p><p>three four</p>'); const redSpan = E.node.querySelector('span'); let r = document.createRange(); r.selectNodeContents(redSpan); let s = window.getSelection(); s.removeAllRanges(); s.addRange(r); E.saveRange(); WC.Commands.run({ cmd: 'formatPainter' }, document.createElement('button')); const ps = E.node.querySelectorAll('p'); const before = ps.length; r = document.createRange(); r.setStart(ps[1].firstChild, 0); r.setEnd(ps[2].firstChild, ps[2].firstChild.length); s.removeAllRanges(); s.addRange(r); E.saveRange(); E.node.dispatchEvent(new MouseEvent('mouseup', { bubbles: true })); const after = E.node.querySelectorAll('p'); const spanWrapsBlock = Array.from(E.node.querySelectorAll('span')).some((sp) => sp.querySelector('p')); return after.length === before && !spanWrapsBlock && /one two/.test(after[1].textContent); });
