  await t('[bb] Footnote inserted ahead of another lands earlier in the notes list', () => { E.setHTML('<p>AAA BBB CCC</p>'); const p = E.node.querySelector('p'); let r = document.createRange(); r.setStart(p.firstChild, p.firstChild.length); r.collapse(true); let s = window.getSelection(); s.removeAllRanges(); s.addRange(r); E.saveRange(); WC.Ref.insertNote('footnote'); E.node.querySelector('.wc-footnotes .wc-note').dataset.tag = 'END'; const tn = E.node.querySelector('p').firstChild; r = document.createRange(); r.setStart(tn, 0); r.collapse(true); s.removeAllRanges(); s.addRange(r); E.saveRange(); WC.Ref.insertNote('footnote'); const notes = E.node.querySelectorAll('.wc-footnotes .wc-note'); return notes.length === 2 && notes[0].dataset.tag !== 'END' && notes[1].dataset.tag === 'END'; });
